-- =====================================================================
-- Mock data seed: two disaster scenarios for map / algorithm testing
-- =====================================================================
-- Scenario A | 花蓮光復泥石流 (2024-07-24, 凱米颱風 +2 天)  — 16 stations
--   集中型大站、官方/NGO 為主、資料品質高;少數市民自發非正式站、部分滿載負評
-- Scenario B | 宜蘭冬山水災   (2025-10-03, 強降雨 +1 天)   — 9 stations
--   里民自發、source 多為 user、updated_at 落後、重複回報、退水後關閉未更新
--
-- Design notes:
--   * joined-table 多型: base_geometries (geometry/時間) -> stations -> station_properties (EAV)
--   * station_properties 無通用 value 欄位: 整數值放 quantity、其餘(bool/enum/array/text)放 comment
--   * source: 以 Google Sheet 規格為準 (gov / user);DB 欄位為自由字串,後端不依此分支
--   * 座標: 錨定真實地標/聚落,落在正確鄉鎮 (誤差約數十~數百公尺,適用地圖測試)
--   * 固定 UUID 前綴方便重跑: 市民 user=c…、場景A站=a…、場景B站=b…
--
-- Idempotent: 腳本開頭會先刪除自身 seed (依 UUID 前綴),可安全重複執行。
-- Run (local dev):  psql "host=127.0.0.1 port=5432 user=postgres dbname=postgres" \
--                     -f scripts/seed_mock_scenarios.sql
-- Run (staging VM): docker compose -f docker-compose.staging.yml exec -T db \
--                     psql -U postgres -d postgres -v ON_ERROR_STOP=1 < scripts/seed_mock_scenarios.sql
--                   (ON_ERROR_STOP=1 is required: without it psql exits 0 on mid-file errors.)
-- =====================================================================

BEGIN;

-- ---------------------------------------------------------------------
-- 0. 清除既有 seed (可重跑)
-- ---------------------------------------------------------------------
DELETE FROM crowd_sourcing
 WHERE station_uuid::text LIKE 'a0000000-%' OR station_uuid::text LIKE 'b0000000-%';
DELETE FROM station_properties
 WHERE station_uuid::text LIKE 'a0000000-%' OR station_uuid::text LIKE 'b0000000-%';
DELETE FROM stations
 WHERE uuid::text LIKE 'a0000000-%' OR uuid::text LIKE 'b0000000-%';
DELETE FROM base_geometries
 WHERE uuid::text LIKE 'a0000000-%' OR uuid::text LIKE 'b0000000-%';
-- 登入憑證(FK 順序: assign/identity/contact 先於 users)
DELETE FROM user_group_assign WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM user_identities   WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM user_contacts     WHERE user_uuid::text LIKE 'c0000000-%';
DELETE FROM users
 WHERE uuid::text LIKE 'c0000000-%';

-- ---------------------------------------------------------------------
-- 1. Mock 市民 / 單位 users (password 可為 NULL;credibility 各異)
-- ---------------------------------------------------------------------

-- =====================================================================
-- SCENARIO A — 花蓮光復泥石流 (16 stations)
-- =====================================================================

-- 1A. base_geometries  (geometry = Point(lng,lat) SRID 4326;updated_at 新鮮=高品質)

-- 2A. stations

-- 3A. station_properties (EAV;整數→quantity、其餘→comment)

-- 4A. crowd_sourcing (官方站多正評;A04 自發滿載、A14 收容滿載 → 負評)

-- =====================================================================
-- SCENARIO B — 宜蘭冬山水災 (9 stations)
-- 自發為主、updated_at 落後、重複回報 (B07/B08)、退水後關閉未更新 (B06)
-- =====================================================================

-- 1B. base_geometries  (注意部分 updated_at 刻意落後,模擬資訊不新鮮)

-- 2B. stations

-- 3B. station_properties (資料較稀疏,反映自發站品質)

-- 4B. crowd_sourcing (混亂、負評較多;B06 退站仍被回報、B08 重複)

-- =====================================================================
-- 關聯一致性修正 (F / G / H) — 讓「誰建立→誰更新→誰投票」自洽
-- =====================================================================
-- H. 自評票改派給第三方 user(避開重複投票,credibility 同步更正)
UPDATE crowd_sourcing SET user_uuid='419dec1e-6875-412d-a043-83ab7d55a860', user_credibility_score=50
 WHERE station_uuid='a0000000-0000-4000-8000-000000000004' AND user_uuid='c0000000-0000-4000-8000-000000000003';
UPDATE crowd_sourcing SET user_uuid='fb43b16d-4bca-4a5b-b5d2-f4afe84c1eec', user_credibility_score=50
 WHERE station_uuid='b0000000-0000-4000-8000-000000000003' AND user_uuid='c0000000-0000-4000-8000-000000000006';
UPDATE crowd_sourcing SET user_uuid='fb43b16d-4bca-4a5b-b5d2-f4afe84c1eec', user_credibility_score=50
 WHERE station_uuid='b0000000-0000-4000-8000-000000000004' AND user_uuid='c0000000-0000-4000-8000-000000000007';
UPDATE crowd_sourcing SET user_uuid='c0000000-0000-4000-8000-000000000007', user_credibility_score=55
 WHERE station_uuid='b0000000-0000-4000-8000-000000000005' AND user_uuid='c0000000-0000-4000-8000-000000000006';
UPDATE crowd_sourcing SET user_uuid='fb43b16d-4bca-4a5b-b5d2-f4afe84c1eec', user_credibility_score=50
 WHERE station_uuid='b0000000-0000-4000-8000-000000000006' AND user_uuid='c0000000-0000-4000-8000-000000000006';
UPDATE crowd_sourcing SET user_uuid='c0000000-0000-4000-8000-000000000006', user_credibility_score=25
 WHERE station_uuid='b0000000-0000-4000-8000-000000000007' AND user_uuid='c0000000-0000-4000-8000-000000000005';
UPDATE crowd_sourcing SET user_uuid='419dec1e-6875-412d-a043-83ab7d55a860', user_credibility_score=50
 WHERE station_uuid='b0000000-0000-4000-8000-000000000008' AND user_uuid='c0000000-0000-4000-8000-000000000006';
UPDATE crowd_sourcing SET user_uuid='c0000000-0000-4000-8000-000000000006', user_credibility_score=25
 WHERE station_uuid='b0000000-0000-4000-8000-000000000009' AND user_uuid='c0000000-0000-4000-8000-000000000007';

-- F. B01 接駁站 / B04 醫療站 改掛宜蘭官方帳號(c…08),名實相符
UPDATE base_geometries SET created_by='c0000000-0000-4000-8000-000000000008'
 WHERE uuid IN ('b0000000-0000-4000-8000-000000000001','b0000000-0000-4000-8000-000000000004');
UPDATE station_properties SET created_by='c0000000-0000-4000-8000-000000000008'
 WHERE station_uuid IN ('b0000000-0000-4000-8000-000000000001','b0000000-0000-4000-8000-000000000004');

-- G. updated_at 晚於 created_at 的站,補 updated_by = 維護者(created_by)。須在 F 之後執行。
UPDATE stations s SET updated_by = g.created_by
 FROM base_geometries g
 WHERE s.uuid=g.uuid AND s.uuid::text ~ '^[ab]0000000-'
   AND g.updated_at > g.created_at AND s.updated_by IS NULL;

-- =====================================================================
-- 登入憑證 — 讓 8 個 mock user 能登入 (方式: 真實密碼登入)
-- =====================================================================
-- 明文密碼: Mock1234!   salt_frontend: mockdata12345678 (8 個共用)
--   * UI 登入: 直接輸入 Mock1234!(FE 會做 sha256(明文+salt) 再送)
--   * API 登入: password 欄位送 sha256("Mock1234!"+"mockdata12345678")
--     = 3a88d3527a01c374689c19033f45ecfad25a749ade957b3044591ad30551e79a
-- password_hash 為 pbkdf2_sha256$iters$salt_frontend$salt_backend$hash(8 個共用同一組,皆驗證 Mock1234!)

SELECT gen_random_uuid(), u, 'password', NULL,
       'pbkdf2_sha256$600000$mockdata12345678$22c5f18b05a3da2d9b73ce908b1b0209$2e9aa846631acac187bcd7c2373fe94702ff7d57fdd1af73a7f258dea4c11a4d',
       now()
FROM unnest(ARRAY[
 'c0000000-0000-4000-8000-000000000001','c0000000-0000-4000-8000-000000000002',
 'c0000000-0000-4000-8000-000000000003','c0000000-0000-4000-8000-000000000004',
 'c0000000-0000-4000-8000-000000000005','c0000000-0000-4000-8000-000000000006',
 'c0000000-0000-4000-8000-000000000007','c0000000-0000-4000-8000-000000000008']::uuid[]) AS u;

-- 群組以名稱查 uuid(跨環境可攜,不寫死 group uuid)
SELECT gen_random_uuid(), u, (SELECT uuid FROM groups WHERE name='Login User')
FROM unnest(ARRAY[
 'c0000000-0000-4000-8000-000000000001','c0000000-0000-4000-8000-000000000002',
 'c0000000-0000-4000-8000-000000000003','c0000000-0000-4000-8000-000000000004',
 'c0000000-0000-4000-8000-000000000005','c0000000-0000-4000-8000-000000000006',
 'c0000000-0000-4000-8000-000000000007','c0000000-0000-4000-8000-000000000008']::uuid[]) AS u;

COMMIT;

